    using StopFn=void(__fastcall*)(void*,void*);
    using CancelFn=void(__fastcall*)(void*,void*);
    using ControllerStopFn=void(__fastcall*)(void*);
    using ControllerMoveFn=void*(__fastcall*)(void*,void*,const void*,void*);
    using ControllerPathCommitFn=void*(__fastcall*)(void*,void*,const void*,void*);
