    struct ClassHooks{void** vtable=nullptr;void* moveTarget=nullptr;void* stopTarget=nullptr;void* cancelTarget=nullptr;MoveRequestFn originalMove=nullptr;StopFn originalStop=nullptr;CancelFn originalCancel=nullptr;bool live=false;bool ownsInstallation=false;};
