    struct MovementClassHooks{void** vtable=nullptr;void* canStartTarget=nullptr;MovementCanStartFn originalCanStart=nullptr;bool live=false;bool ownsInstallation=false;};
    struct MovementComponent{UE::UObject* guard=nullptr;UE::UObject* movement=nullptr;void** vtable=nullptr;bool forceCanStart=false;};
    struct ControllerComponent{UE::UObject* guard=nullptr;UE::UObject* controller=nullptr;void** vtable=nullptr;bool owned=false;};
    struct PathComponent{UE::UObject* guard=nullptr;UE::UObject* controller=nullptr;UE::UObject* pathFollower=nullptr;void** vtable=nullptr;};

