bool ResolveHelpers(UE::UObject* moveFn,UE::UObject* forceFn)
{
    std::lock_guard<std::mutex> lock(g_mutex);
    if(!g_moveToLocation&&moveFn){auto* exec=static_cast<std::uint8_t*>(NativeExec(moveFn));static const std::uint8_t execPrefix[]={0x48,0x89,0x5C,0x24,0x08,0x48,0x89,0x6C,0x24,0x18,0x56,0x57,0x41,0x56,0x48,0x83};static const std::uint8_t targetPrefix[]={0x4C,0x8B,0xDC,0x48,0x83,0xEC,0x68,0x8B,0x42,0x08,0x45,0x33,0xC0};if(exec&&Bytes(exec,execPrefix,sizeof(execPrefix))&&Scanner::IsExecutableAddress(exec+kMoveHelperCall,5)&&exec[kMoveHelperCall]==0xE8){std::uint8_t* target=Scanner::DecodeRel32CallTarget(exec+kMoveHelperCall);if(target&&Bytes(target,targetPrefix,sizeof(targetPrefix))){g_moveToLocation=reinterpret_cast<MoveToLocationFn>(target);LOG_HOOK("[AI-MOVE] Mercuna MoveToLocation helper resolved via ReVa-confirmed callsite -> RVA 0x%llX, sanity PASS.",(unsigned long long)Rva(target));}}if(!g_moveToLocation)LOG_HOOK("[AI-MOVE] Mercuna MoveToLocation helper refused: callsite/target sanity failed.");}
    if(!g_mixedTransition&&forceFn){auto* exec=static_cast<std::uint8_t*>(NativeExec(forceFn));static const std::uint8_t execPrefix[]={0x48,0x89,0x5C,0x24,0x10,0x57,0x48,0x83,0xEC,0x20,0x48,0x8B,0xDA};static const std::uint8_t dispatcherPrefix[]={0x4C,0x8B,0xDC,0x49,0x89,0x5B,0x08,0x57,0x48,0x81,0xEC,0xC0,0x00,0x00,0x00};static const std::uint8_t transitionPrefix[]={0x40,0x53,0x57,0x48,0x83,0xEC,0x28,0x48,0x8B,0x81,0xA0,0x1F,0x00,0x00,0x0F,0xB6,0xFA};if(exec&&Bytes(exec,execPrefix,sizeof(execPrefix))&&Scanner::IsExecutableAddress(exec+kForceDispatcherCall,5)&&exec[kForceDispatcherCall]==0xE8){std::uint8_t* dispatcher=Scanner::DecodeRel32CallTarget(exec+kForceDispatcherCall);if(dispatcher&&Bytes(dispatcher,dispatcherPrefix,sizeof(dispatcherPrefix))&&Scanner::IsExecutableAddress(dispatcher+kTransitionCall,5)&&dispatcher[kTransitionCall]==0xE8){std::uint8_t* transition=Scanner::DecodeRel32CallTarget(dispatcher+kTransitionCall);if(transition&&Bytes(transition,transitionPrefix,sizeof(transitionPrefix))){g_mixedTransition=reinterpret_cast<MixedTransitionFn>(transition);LOG_HOOK("[AI-MOVE] Twin mixed-nav transition resolved via two-stage ReVa callsite chain -> RVA 0x%llX, sanity PASS.",(unsigned long long)Rva(transition));}}}if(!g_mixedTransition)LOG_HOOK("[AI-MOVE] Twin mixed-nav transition refused: callsite chain/target sanity failed.");}
    return g_moveToLocation!=nullptr;
}

